42: /**
43:  * <p>The range assignor works on a per-topic basis. For each topic, we lay out the available partitions in numeric order
44:  * and the consumers in lexicographic order. We then divide the number of partitions by the total number of
45:  * consumers to determine the number of partitions to assign to each consumer. If it does not evenly
46:  * divide, then the first few consumers will have one extra partition.
47:  *
48:  * <p>For example, suppose there are two consumers <code>C0</code> and <code>C1</code>, two topics <code>t0</code> and
49:  * <code>t1</code>, and each topic has 3 partitions, resulting in partitions <code>t0p0</code>, <code>t0p1</code>,
50:  * <code>t0p2</code>, <code>t1p0</code>, <code>t1p1</code>, and <code>t1p2</code>.
51:  *
52:  * <p>The assignment will be:
53:  * <ul>
54:  * <li><code>C0: [t0p0, t0p1, t1p0, t1p1]</code></li>
55:  * <li><code>C1: [t0p2, t1p2]</code></li>
56:  * </ul>
57:  *
58:  * Since the introduction of static membership, we could leverage <code>group.instance.id</code> to make the assignment behavior more sticky.
59:  * For the above example, after one rolling bounce, group coordinator will attempt to assign new <code>member.id</code> towards consumers,
60:  * for example <code>C0</code> -&gt; <code>C3</code> <code>C1</code> -&gt; <code>C2</code>.
61:  *
62:  * <p>The assignment could be completely shuffled to:
63:  * <ul>
64:  * <li><code>C3 (was C0): [t0p2, t1p2] (before was [t0p0, t0p1, t1p0, t1p1])</code>
65:  * <li><code>C2 (was C1): [t0p0, t0p1, t1p0, t1p1] (before was [t0p2, t1p2])</code>
66:  * </ul>
67:  *
68:  * The assignment change was caused by the change of <code>member.id</code> relative order, and
69:  * can be avoided by setting the group.instance.id.
70:  * Consumers will have individual instance ids <code>I1</code>, <code>I2</code>. As long as
71:  * 1. Number of members remain the same across generation
72:  * 2. Static members' identities persist across generation
73:  * 3. Subscription pattern doesn't change for any member
74:  *
75:  * <p>The assignment will always be:
76:  * <ul>
77:  * <li><code>I0: [t0p0, t0p1, t1p0, t1p1]</code>
78:  * <li><code>I1: [t0p2, t1p2]</code>
79:  * </ul>
80:  * <p>
81:  * Rack-aware assignment is used if both consumer and partition replica racks are available and
82:  * some partitions have replicas only on a subset of racks. We attempt to match consumer racks with
83:  * partition replica racks on a best-effort basis, prioritizing balanced assignment over rack alignment.
84:  * Topics with equal partition count and same set of subscribers guarantee co-partitioning by prioritizing
85:  * co-partitioning over rack alignment. In this case, aligning partition replicas of these topics on the
86:  * same racks will improve locality for consumers. For example, if partitions 0 of all topics have a replica
87:  * on rack 'a', partition 1 on rack 'b' etc., partition 0 of all topics can be assigned to a consumer
88:  * on rack 'a', partition 1 to a consumer on rack 'b' and so on.
89:  * <p>
90:  * Note that rack-aware assignment currently takes all replicas into account, including any offline replicas
91:  * and replicas that are not in the ISR. This is based on the assumption that these replicas are likely
92:  * to join the ISR relatively soon. Since consumers don't rebalance on ISR change, this avoids unnecessary
93:  * cross-rack traffic for long durations after replicas rejoin the ISR. In the future, we may consider
94:  * rebalancing when replicas are added or removed to improve consumer rack alignment.
95:  * </p>
96:  */
97: public class RangeAssignor extends AbstractPartitionAssignor {
98:     public static final String RANGE_ASSIGNOR_NAME = "range";
99:     private static final TopicPartitionComparator PARTITION_COMPARATOR = new TopicPartitionComparator();
100: 
101:     @Override
102:     public String name() {
103:         return RANGE_ASSIGNOR_NAME;
104:     }
105: 
106:     private Map<String, List<MemberInfo>> consumersPerTopic(Map<String, Subscription> consumerMetadata) {
107:         Map<String, List<MemberInfo>> topicToConsumers = new HashMap<>();
108:         consumerMetadata.forEach((consumerId, subscription) -> {
109:             MemberInfo memberInfo = new MemberInfo(consumerId, subscription.groupInstanceId(), subscription.rackId());
110:             subscription.topics().forEach(topic -> put(topicToConsumers, topic, memberInfo));
111:         });
112:         return topicToConsumers;
113:     }
114: 
115:     /**
116:      * Performs range assignment of the specified partitions for the consumers with the provided subscriptions.
117:      * If rack-awareness is enabled for one or more consumers, we perform rack-aware assignment first to assign
118:      * the subset of partitions that can be aligned on racks, while retaining the same co-partitioning and
119:      * per-topic balancing guarantees as non-rack-aware range assignment. The remaining partitions are assigned
120:      * using standard non-rack-aware range assignment logic, which may result in mis-aligned racks.
121:      */
122:     @Override
123:     public Map<String, List<TopicPartition>> assignPartitions(Map<String, List<PartitionInfo>> partitionsPerTopic,
124:                                                               Map<String, Subscription> subscriptions) {
125:         Map<String, List<MemberInfo>> consumersPerTopic = consumersPerTopic(subscriptions);
126:         Map<String, String> consumerRacks = consumerRacks(subscriptions);
127:         List<TopicAssignmentState> topicAssignmentStates = partitionsPerTopic.entrySet().stream()
128:                 .filter(e -> !e.getValue().isEmpty())
129:                 .map(e -> new TopicAssignmentState(e.getKey(), e.getValue(), consumersPerTopic.get(e.getKey()), consumerRacks))
130:                 .collect(Collectors.toList());
131: 
132:         Map<String, List<TopicPartition>> assignment = new HashMap<>();
133:         subscriptions.keySet().forEach(memberId -> assignment.put(memberId, new ArrayList<>()));
134: 
135:         boolean useRackAware = topicAssignmentStates.stream().anyMatch(t -> t.needsRackAwareAssignment);
136:         if (useRackAware)
137:             assignWithRackMatching(topicAssignmentStates, assignment);
138: 
139:         topicAssignmentStates.forEach(t -> assignRanges(t, (c, tp) -> true, assignment));
140: 
141:         if (useRackAware)
142:             assignment.values().forEach(list -> list.sort(PARTITION_COMPARATOR));
143:         return assignment;
144:     }
145: 
146:     // This method is not used, but retained for compatibility with any custom assignors that extend this class.
147:     @Override
148:     public Map<String, List<TopicPartition>> assign(Map<String, Integer> partitionsPerTopic,
149:                                                     Map<String, Subscription> subscriptions) {
150:         return assignPartitions(partitionInfosWithoutRacks(partitionsPerTopic), subscriptions);
151:     }
152: 
153:     private void assignRanges(TopicAssignmentState assignmentState,
154:                               BiFunction<String, TopicPartition, Boolean> mayAssign,
155:                               Map<String, List<TopicPartition>> assignment) {
156:         for (String consumer : assignmentState.consumers.keySet()) {
157:             if (assignmentState.unassignedPartitions.isEmpty())
158:                 break;
159:             List<TopicPartition> assignablePartitions = assignmentState.unassignedPartitions.stream()
160:                     .filter(tp -> mayAssign.apply(consumer, tp))
161:                     .limit(assignmentState.maxAssignable(consumer))
162:                     .collect(Collectors.toList());
163:             if (assignablePartitions.isEmpty())
164:                 continue;
165: 
166:             assign(consumer, assignablePartitions, assignmentState, assignment);
167:         }
168:     }
169: 
170:     private void assignWithRackMatching(Collection<TopicAssignmentState> assignmentStates,
171:                                         Map<String, List<TopicPartition>> assignment) {
172: 
173:         assignmentStates.stream().collect(Collectors.groupingBy(t -> t.consumers)).forEach((consumers, states) ->
174:             states.stream().collect(Collectors.groupingBy(t -> t.partitionRacks.size())).forEach((numPartitions, coPartitionedStates) -> {
175:                 if (coPartitionedStates.size() > 1)
176:                     assignCoPartitionedWithRackMatching(consumers, numPartitions, coPartitionedStates, assignment);
177:                 else {
178:                     TopicAssignmentState state = coPartitionedStates.get(0);
179:                     if (state.needsRackAwareAssignment)
180:                         assignRanges(state, state::racksMatch, assignment);
181:                 }
182:             })
183:         );
184:     }
185: 
186:     private void assignCoPartitionedWithRackMatching(LinkedHashMap<String, Optional<String>> consumers,
187:                                                      int numPartitions,
188:                                                      Collection<TopicAssignmentState> assignmentStates,
189:                                                      Map<String, List<TopicPartition>> assignment) {
190: 
191:         Set<String> remainingConsumers = new LinkedHashSet<>(consumers.keySet());
192:         for (int i = 0; i < numPartitions; i++) {
193:             int p = i;
194: 
195:             Optional<String> matchingConsumer = remainingConsumers.stream()
196:                     .filter(c -> assignmentStates.stream().allMatch(t -> t.racksMatch(c, new TopicPartition(t.topic, p)) && t.maxAssignable(c) > 0))
197:                     .findFirst();
198:             if (matchingConsumer.isPresent()) {
199:                 String consumer = matchingConsumer.get();
200:                 assignmentStates.forEach(t -> assign(consumer, Collections.singletonList(new TopicPartition(t.topic, p)), t, assignment));
201: 
202:                 if (assignmentStates.stream().noneMatch(t -> t.maxAssignable(consumer) > 0)) {
203:                     remainingConsumers.remove(consumer);
204:                     if (remainingConsumers.isEmpty())
205:                         break;
206:                 }
207:             }
208:         }
209:     }
210: 
211:     private void assign(String consumer, List<TopicPartition> partitions, TopicAssignmentState assignmentState, Map<String, List<TopicPartition>> assignment) {
212:         assignment.get(consumer).addAll(partitions);
213:         assignmentState.onAssigned(consumer, partitions);
214:     }
215: 
216:     private Map<String, String> consumerRacks(Map<String, Subscription> subscriptions) {
217:         Map<String, String> consumerRacks = new HashMap<>(subscriptions.size());
218:         subscriptions.forEach((memberId, subscription) ->
219:                 subscription.rackId().filter(r -> !r.isEmpty()).ifPresent(rackId -> consumerRacks.put(memberId, rackId)));
220:         return consumerRacks;
221:     }
222: 
223:     private class TopicAssignmentState {
224:         private final String topic;
225:         private final LinkedHashMap<String, Optional<String>> consumers;
226:         private final boolean needsRackAwareAssignment;
227:         private final Map<TopicPartition, Set<String>> partitionRacks;
228: 
229:         private final Set<TopicPartition> unassignedPartitions;
230:         private final Map<String, Integer> numAssignedByConsumer;
231:         private final int numPartitionsPerConsumer;
232:         private int remainingConsumersWithExtraPartition;
233: 
234:         public TopicAssignmentState(String topic, List<PartitionInfo> partitionInfos, List<MemberInfo> membersOrNull, Map<String, String> consumerRacks) {
235:             this.topic = topic;
236:             List<MemberInfo> members = membersOrNull == null ? Collections.emptyList() : membersOrNull;
237:             Collections.sort(members);
238:             consumers = members.stream().map(c -> c.memberId)
239:                     .collect(Collectors.toMap(Function.identity(), c -> Optional.ofNullable(consumerRacks.get(c)), (a, b) -> a, LinkedHashMap::new));
240: 
241:             this.unassignedPartitions = partitionInfos.stream().map(p -> new TopicPartition(p.topic(), p.partition()))
242:                     .collect(Collectors.toCollection(LinkedHashSet::new));
243:             this.numAssignedByConsumer = consumers.keySet().stream().collect(Collectors.toMap(Function.identity(), c -> 0));
244:             numPartitionsPerConsumer = consumers.isEmpty() ? 0 : partitionInfos.size() / consumers.size();
245:             remainingConsumersWithExtraPartition = consumers.isEmpty() ? 0 : partitionInfos.size() % consumers.size();
246: 
247:             Set<String> allConsumerRacks = new HashSet<>();
248:             Set<String> allPartitionRacks = new HashSet<>();
249:             members.stream().map(m -> m.memberId).filter(consumerRacks::containsKey)
250:                     .forEach(memberId -> allConsumerRacks.add(consumerRacks.get(memberId)));
251:             if (!allConsumerRacks.isEmpty()) {
252:                 partitionRacks = new HashMap<>(partitionInfos.size());
253:                 partitionInfos.forEach(p -> {
254:                     TopicPartition tp = new TopicPartition(p.topic(), p.partition());
255:                     Set<String> racks = Arrays.stream(p.replicas())
256:                             .map(Node::rack)
257:                             .filter(Objects::nonNull)
258:                             .collect(Collectors.toSet());
259:                     partitionRacks.put(tp, racks);
260:                     allPartitionRacks.addAll(racks);
261:                 });
262:             } else {
263:                 partitionRacks = Collections.emptyMap();
264:             }
265: 
266:             needsRackAwareAssignment = useRackAwareAssignment(allConsumerRacks, allPartitionRacks, partitionRacks);
267:         }
268: 
269:         boolean racksMatch(String consumer, TopicPartition tp) {
270:             Optional<String> consumerRack = consumers.get(consumer);
271:             Set<String> replicaRacks = partitionRacks.get(tp);
272:             return consumerRack.isEmpty() || (replicaRacks != null && replicaRacks.contains(consumerRack.get()));
273:         }
274: 
275:         int maxAssignable(String consumer) {
276:             int maxForConsumer = numPartitionsPerConsumer + (remainingConsumersWithExtraPartition > 0 ? 1 : 0) - numAssignedByConsumer.get(consumer);
277:             return Math.max(0, maxForConsumer);
278:         }
279: 
280:         void onAssigned(String consumer, List<TopicPartition> newlyAssignedPartitions) {
281:             int numAssigned = numAssignedByConsumer.compute(consumer, (c, n) -> n + newlyAssignedPartitions.size());
282:             if (numAssigned > numPartitionsPerConsumer)
283:                 remainingConsumersWithExtraPartition--;
284:             unassignedPartitions.removeAll(newlyAssignedPartitions);
285:         }
286: 
287:         @Override
