36: /**
37:  * A cooperative version of the {@link AbstractStickyAssignor AbstractStickyAssignor}. This follows the same (sticky)
38:  * assignment logic as {@link StickyAssignor StickyAssignor} but allows for cooperative rebalancing while the
39:  * {@link StickyAssignor StickyAssignor} follows the eager rebalancing protocol. See
40:  * {@link ConsumerPartitionAssignor.RebalanceProtocol} for an explanation of the rebalancing protocols.
41:  * <p>
42:  * Users should prefer this assignor for newer clusters.
43:  * <p>
44:  * To turn on cooperative rebalancing you must set all your consumers to use this {@code PartitionAssignor},
45:  * or implement a custom one that returns {@code RebalanceProtocol.COOPERATIVE} in
46:  * {@link CooperativeStickyAssignor#supportedProtocols supportedProtocols()}.
47:  * <p>
48:  * IMPORTANT: if upgrading from 2.3 or earlier, you must follow a specific upgrade path in order to safely turn on
49:  * cooperative rebalancing. See the <a href="https://kafka.apache.org/documentation/#upgrade_240_notable">upgrade guide</a> for details.
50:  */
51: public class CooperativeStickyAssignor extends AbstractStickyAssignor {
52:     public static final String COOPERATIVE_STICKY_ASSIGNOR_NAME = "cooperative-sticky";
53: 
54:     // these schemas are used for preserving useful metadata for the assignment, such as the last stable generation
55:     private static final String GENERATION_KEY_NAME = "generation";
56:     private static final Schema COOPERATIVE_STICKY_ASSIGNOR_USER_DATA_V0 = new Schema(
57:         new Field(GENERATION_KEY_NAME, Type.INT32));
58: 
59:     private int generation = DEFAULT_GENERATION; // consumer group generation
60: 
61:     @Override
62:     public String name() {
63:         return COOPERATIVE_STICKY_ASSIGNOR_NAME;
64:     }
65: 
66:     @Override
67:     public List<RebalanceProtocol> supportedProtocols() {
68:         return Arrays.asList(RebalanceProtocol.COOPERATIVE, RebalanceProtocol.EAGER);
69:     }
70: 
71:     @Override
72:     public void onAssignment(Assignment assignment, ConsumerGroupMetadata metadata) {
73:         this.generation = metadata.generationId();
74:     }
75: 
76:     @Override
77:     public ByteBuffer subscriptionUserData(Set<String> topics) {
78:         Struct struct = new Struct(COOPERATIVE_STICKY_ASSIGNOR_USER_DATA_V0);
79: 
80:         struct.set(GENERATION_KEY_NAME, generation);
81:         ByteBuffer buffer = ByteBuffer.allocate(COOPERATIVE_STICKY_ASSIGNOR_USER_DATA_V0.sizeOf(struct));
82:         COOPERATIVE_STICKY_ASSIGNOR_USER_DATA_V0.write(buffer, struct);
83:         buffer.flip();
84:         return buffer;
85:     }
86: 
87:     @Override
88:     protected MemberData memberData(Subscription subscription) {
89:         // In ConsumerProtocolSubscription v2 or higher, we can take member data from fields directly
90:         if (subscription.generationId().isPresent()) {
91:             return new MemberData(subscription.ownedPartitions(), subscription.generationId());
92:         }
93: 
94:         ByteBuffer buffer = subscription.userData();
95:         Optional<Integer> encodedGeneration;
96:         if (buffer == null) {
97:             encodedGeneration = Optional.empty();
98:         } else {
99:             try {
100:                 Struct struct = COOPERATIVE_STICKY_ASSIGNOR_USER_DATA_V0.read(buffer);
101:                 encodedGeneration = Optional.of(struct.getInt(GENERATION_KEY_NAME));
102:             } catch (Exception e) {
103:                 encodedGeneration = Optional.of(DEFAULT_GENERATION);
104:             }
105:         }
106:         return new MemberData(subscription.ownedPartitions(), encodedGeneration, subscription.rackId());
107:     }
108: 
109:     @Override
110:     public Map<String, List<TopicPartition>> assignPartitions(Map<String, List<PartitionInfo>> partitionsPerTopic,
111:                                                               Map<String, Subscription> subscriptions) {
112:         Map<String, List<TopicPartition>> assignments = super.assignPartitions(partitionsPerTopic, subscriptions);
113: 
114:         Map<TopicPartition, String> partitionsTransferringOwnership = super.partitionsTransferringOwnership == null ?
115:             computePartitionsTransferringOwnership(subscriptions, assignments) :
116:             super.partitionsTransferringOwnership;
117: 
118:         adjustAssignment(assignments, partitionsTransferringOwnership);
119:         return assignments;
120:     }
121: 
122:     // Following the cooperative rebalancing protocol requires removing partitions that must first be revoked from the assignment
123:     private void adjustAssignment(Map<String, List<TopicPartition>> assignments,
124:                                   Map<TopicPartition, String> partitionsTransferringOwnership) {
125:         for (Map.Entry<TopicPartition, String> partitionEntry : partitionsTransferringOwnership.entrySet()) {
126:             assignments.get(partitionEntry.getValue()).remove(partitionEntry.getKey());
127:         }
128:     }
129: 
130:     private Map<TopicPartition, String> computePartitionsTransferringOwnership(Map<String, Subscription> subscriptions,
131:                                                                                Map<String, List<TopicPartition>> assignments) {
132:         Map<TopicPartition, String> allAddedPartitions = new HashMap<>();
133:         Set<TopicPartition> allRevokedPartitions = new HashSet<>();
134: 
135:         for (final Map.Entry<String, List<TopicPartition>> entry : assignments.entrySet()) {
136:             String consumer = entry.getKey();
137: 
138:             List<TopicPartition> ownedPartitions = subscriptions.get(consumer).ownedPartitions();
139:             List<TopicPartition> assignedPartitions = entry.getValue();
140: 
141:             Set<TopicPartition> ownedPartitionsSet = new HashSet<>(ownedPartitions);
142:             for (TopicPartition tp : assignedPartitions) {
143:                 if (!ownedPartitionsSet.contains(tp))
144:                     allAddedPartitions.put(tp, consumer);
145:             }
146: 
147:             Set<TopicPartition> assignedPartitionsSet = new HashSet<>(assignedPartitions);
148:             for (TopicPartition tp : ownedPartitions) {
149:                 if (!assignedPartitionsSet.contains(tp))
150:                     allRevokedPartitions.add(tp);
151:             }
152:         }
153: 
154:         allAddedPartitions.keySet().retainAll(allRevokedPartitions);
155:         return allAddedPartitions;
156:     }
157: }
