134:     public static class MemberInfo implements Comparable<MemberInfo> {
135:         public final String memberId;
136:         public final Optional<String> groupInstanceId;
137:         public final Optional<String> rackId;
138: 
139:         public MemberInfo(String memberId, Optional<String> groupInstanceId, Optional<String> rackId) {
140:             this.memberId = memberId;
141:             this.groupInstanceId = groupInstanceId;
142:             this.rackId = rackId;
143:         }
144: 
145:         public MemberInfo(String memberId, Optional<String> groupInstanceId) {
146:             this(memberId, groupInstanceId, Optional.empty());
147:         }
148: 
149:         @Override
150:         public int compareTo(MemberInfo otherMemberInfo) {
151:             if (this.groupInstanceId.isPresent() &&
152:                     otherMemberInfo.groupInstanceId.isPresent()) {
153:                 return this.groupInstanceId.get()
154:                         .compareTo(otherMemberInfo.groupInstanceId.get());
155:             } else if (this.groupInstanceId.isPresent()) {
156:                 return -1;
157:             } else if (otherMemberInfo.groupInstanceId.isPresent()) {
158:                 return 1;
159:             } else {
160:                 return this.memberId.compareTo(otherMemberInfo.memberId);
161:             }
162:         }
163: 
164:         @Override
165:         public boolean equals(Object o) {
166:             return o instanceof MemberInfo && this.memberId.equals(((MemberInfo) o).memberId);
167:         }
168: 
169:         /**
170:          * We could just use member.id to be the hashcode, since it's unique
171:          * across the group.
172:          */
173:         @Override
174:         public int hashCode() {
175:             return memberId.hashCode();
176:         }
177: 
178:         @Override
179:         public String toString() {
180:             return "MemberInfo [member.id: " + memberId
181:                     + ", group.instance.id: " + groupInstanceId.orElse("{}")
182:                     + "]";
183:         }
184:     }
185: }
